+                    .path()
+                    .strip_prefix(root)
+                    .unwrap_or(e.path())
+                    .to_string_lossy()
+                    .into_owned();
+                let len = e.metadata().map(|m| m.len()).unwrap_or(0);
+                (rel, len)
+            })
+            .collect();
+        entries.sort();
+        entries
